#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
const int MAXN = 20005;
int K, N, C;
int ans;
struct Node {
	int maxv, add;
};
struct Edge {
	int s, e, m;
};
Node tree[MAXN << 2];
Edge group[50005];
bool cmp (Edge x, Edge y) {
	if (x.e != y.e) {
		return x.e < y.e;
	}
	return x.s < y.s;
}
void pushup (int p) {
	tree[p].maxv = max (tree[p << 1].maxv, tree[p << 1 | 1].maxv);
	return;
}
void pushdown (int p) {
	if (tree[p].add) {
		int add = tree[p].add;
		tree[p << 1].add += add;
		tree[p << 1 | 1].add += add;
		tree[p << 1].maxv += add;
		tree[p << 1 | 1].maxv += add;
		tree[p].add = 0;
	}
	return;
}
void build (int p, int L, int R) {
	tree[p].add = 0, tree[p].maxv = 0;
	if (L == R) {
		return;
	}
	int mid = (L + R) >> 1;
	build (p << 1, L, mid);
	build (p << 1 | 1, mid + 1, R);
	return;
}
void modify (int p, int L, int R, int qL, int qR, int val) {
    if (qL <= L && R <= qR) {
        tree[p].maxv += val;
        tree[p].add += val;
        return;
    }
    pushdown(p);
    int mid = (L + R) >> 1;
    if (qL <= mid) {
    	modify (p << 1, L, mid, qL, qR, val);
	}
    if (qR > mid) {
    	modify (p << 1 | 1, mid + 1, R, qL, qR, val);
	}
    pushup (p);
}
int query(int p, int L, int R, int qL, int qR) {
    if (qL <= L && R <= qR) {
        return tree[p].maxv;
    }
    pushdown (p);
    int mid = (L + R) >> 1;
    int res = 0;
    if (qL <= mid) {
    	res = max (res, query (p << 1, L, mid, qL, qR));
	}
    if (qR > mid) {
    	res = max (res, query (p << 1 | 1, mid + 1, R, qL, qR));
	}
    return res;
}
signed main() {
	cin >> K >> N >> C;
	for (int i = 1; i <= K; i++) {
		cin >> group[i].s >> group[i].e >> group[i].m;
	}
	sort (group + 1, group + K + 1, cmp);
	build (1, 1, N);
	for (int i = 1; i <= K; i++) {
		int s = group[i].s;
		int e = group[i].e;
		int m = group[i].m;
		int mx = query (1, 1, N, s, e - 1);
		int x = min (C - mx, m);
		if (x > 0) {
			ans += x;
			modify (1, 1, N, s, e - 1, x);
		}
	}
	cout << ans;
	return 0;
}
